mapper.select:
SELECT id, alert_id, alert_no, alert_type, alert_type_name, alert_level, person_id, person_name, longitude, latitude, location_desc, probability, predict_time, status, status_name, crowd_count, target_person_count, create_time FROM prediction_alert WHERE create_time BETWEEN #{startTime} AND #{endTime}
AND alert_level >= #{alertLevel}
AND deleted = 0 ORDER BY alert_level DESC, create_time DESC
